import { NgComponentOutlet } from '@angular/common';
import { ChangeDetectionStrategy, Component, Injector, computed, inject, input } from '@angular/core';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { fakerPT_BR as faker } from '@faker-js/faker';
import type { Decorator, Meta, StoryObj } from '@storybook/angular';
import { expect, userEvent, within } from 'storybook/test';
import { of } from 'rxjs';
import { ScannerFeedbackService } from '@cacic-fct/shared-angular';
import { AttendanceApiService } from '../../graphql/attendance-api.service';
import type { AttendanceCategory, EventAttendance, EventAttendanceScannerFeedItem } from '../../graphql/models';
import { WorkspaceAttendanceScannerDialogComponent } from './workspace-attendance-scanner-dialog.component';

faker.seed(20260616);

type AttendanceScannerStoryArgs = {
  eventId: string;
  feedCount: number;
  category: AttendanceCategory;
};

const dialogRefMock = {
  close: () => undefined,
};

function scannerFeedItem(index: number, eventId: string): EventAttendanceScannerFeedItem {
  return {
    eventId,
    personId: `person-${index + 1}`,
    fullName: faker.person.fullName(),
    unespRole: faker.helpers.arrayElement(['GRADUATION_STUDENT', 'GRADUATE_STUDENT', 'EXTERNAL_COMMUNITY']),
    subscriptionStatus: faker.helpers.arrayElement(['CONFIRMED', 'WAITING_RECEIPT_UPLOAD', null]),
    attendedAt: faker.date.recent({ days: 2 }).toISOString(),
    createdByMethod: index % 2 === 0 ? 'SCANNER' : 'MANUAL_INPUT',
    collectedByFirstName: faker.person.firstName(),
  };
}

function attendance(eventId: string, category: AttendanceCategory): EventAttendance {
  return {
    eventId,
    personId: 'person-created',
    category,
    attendedAt: new Date('2026-05-21T17:15:00.000Z').toISOString(),
    createdAt: new Date('2026-05-21T17:15:00.000Z').toISOString(),
    createdById: 'storybook-admin',
    createdByMethod: 'MANUAL_INPUT',
  };
}

class StoryAttendanceApiService {
  private eventId = 'event-1';
  private category: AttendanceCategory = 'REGULAR';
  private feed: EventAttendanceScannerFeedItem[] = [];

  configure(args: AttendanceScannerStoryArgs): void {
    faker.seed(20260624 + args.feedCount);
    this.eventId = args.eventId;
    this.category = args.category;
    this.feed = Array.from({ length: args.feedCount }, (_, index) => scannerFeedItem(index, args.eventId));
  }

  listEventAttendanceScannerFeed() {
    return of(this.feed);
  }

  watchEventAttendanceScannerFeed() {
    return of(this.feed);
  }

  createEventAttendanceFromScannerCode() {
    return of(attendance(this.eventId, this.category));
  }

  createEventAttendanceFromManualInput() {
    return of(attendance(this.eventId, this.category));
  }
}

const attendanceApi = new StoryAttendanceApiService();

const cameraDeniedDecorator: Decorator = (story) => {
  if (typeof navigator !== 'undefined') {
    Object.defineProperty(navigator, 'mediaDevices', {
      configurable: true,
      value: {
        getUserMedia: () => Promise.reject(new Error('Permissão negada no Storybook.')),
        enumerateDevices: () => Promise.resolve([]),
      },
    });
  }
  return story();
};

@Component({
  selector: 'app-storybook-attendance-scanner-dialog-host',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [NgComponentOutlet],
  template: `<ng-container *ngComponentOutlet="component; injector: storyInjector()" />`,
})
class WorkspaceAttendanceScannerDialogStoryHostComponent {
  private readonly injector = inject(Injector);

  readonly component = WorkspaceAttendanceScannerDialogComponent;
  readonly eventId = input('event-1');

  readonly storyInjector = computed(() =>
    Injector.create({
      parent: this.injector,
      providers: [
        { provide: MAT_DIALOG_DATA, useValue: { eventId: this.eventId() } },
        { provide: MatDialogRef, useValue: dialogRefMock },
        { provide: AttendanceApiService, useValue: attendanceApi },
        { provide: ScannerFeedbackService, useValue: { show: () => undefined } },
      ],
    }),
  );
}

const meta: Meta<AttendanceScannerStoryArgs> = {
  component: WorkspaceAttendanceScannerDialogStoryHostComponent,
  title: 'CACiC Eventos/Workspace/Dialogs/Workspace Attendance Scanner Dialog',
  tags: ['autodocs'],
  decorators: [cameraDeniedDecorator],
  args: {
    eventId: 'event-1',
    feedCount: 5,
    category: 'REGULAR',
  },
  argTypes: {
    eventId: { control: 'text' },
    feedCount: { control: { type: 'range', min: 0, max: 10, step: 1 } },
    category: { control: 'select', options: ['REGULAR', 'NON_PAYING', 'NON_SUBSCRIBED', 'UNKNOWN'] },
  },
  render: (args) => {
    attendanceApi.configure(args);
    return { props: args };
  },
  parameters: {
    layout: 'fullscreen',
    a11y: { test: 'todo' },
  },
};

export default meta;

type Story = StoryObj<AttendanceScannerStoryArgs>;

export const ScannerReady: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(await canvas.findByText('Escanear presenças')).toBeVisible();
    await userEvent.type(await canvas.findByLabelText(/e-mail, telefone ou documento/i), 'ana@example.com');
  },
};

export const EmptyFeed: Story = {
  args: {
    feedCount: 0,
  },
  };

import { provideHttpClient, withFetch } from '@angular/common/http';
import { inject, provideAppInitializer } from '@angular/core';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { MatIconRegistry } from '@angular/material/icon';
import { provideRouter, withDisabledInitialNavigation } from '@angular/router';
import { provideNoopAnimations } from '@angular/platform-browser/animations';
import { AuthService } from '@cacic-fct/shared-angular';
import { EVENT_MANAGER_PERMISSION_CATALOG } from '@cacic-fct/shared-permissions';
import type { Preview } from '@storybook/angular';
import { applicationConfig } from '@storybook/angular';
import { initialize, mswLoader } from 'msw-storybook-addon';
import { cacicEventosHandlers } from './storybook-mocks';

initialize({
  onUnhandledRequest: 'bypass',
  serviceWorker: {
    url: './mockServiceWorker.js',
    options: {
      scope: './',
    },
  },
});

const originalNavigatorOnline = Object.getOwnPropertyDescriptor(Navigator.prototype, 'onLine');

function ensureStorybookGlobalStyles(): void {
  if (document.getElementById('storybook-app-global-styles')) {
    return;
  }

  const style = document.createElement('style');
  style.id = 'storybook-app-global-styles';
  style.textContent = `
    html, body, #storybook-root {
      min-height: 100%;
    }

    body {
      margin: 0;
      font-family: 'Inter Variable', system-ui, sans-serif;
    }

    @font-face {
      font-family: 'Material Symbols Outlined';
      font-style: normal;
      font-display: swap;
      font-weight: 400;
      src:
        url('./material-symbols-outlined-files/material-symbols-outlined-latin-400-normal.woff2') format('woff2'),
        url('./material-symbols-outlined-files/material-symbols-outlined-latin-400-normal.woff') format('woff');
    }

    .material-symbols-outlined {
      font-family: 'Material Symbols Outlined';
      font-weight: normal;
      font-style: normal;
      font-size: 24px;
      line-height: 1;
      letter-spacing: normal;
      text-transform: none;
      display: inline-block;
      white-space: nowrap;
      word-wrap: normal;
      direction: ltr;
    }
  `;
  document.head.append(style);
}

const dialogRefMock = {
  close: () => undefined,
};

const personA = {
  id: 'person-a',
  name: 'Ana Clara Silva',
  email: 'ana@example.com',
  identityDocument: '12345678901',
  academicId: '2026001',
  userId: 'user-a',
  externalRef: 'ext-a',
};

const personB = {
  id: 'person-b',
  name: 'Ana C. Silva',
  email: 'ana.silva@example.com',
  identityDocument: '12345678901',
  academicId: '2026001',
  userId: null,
  externalRef: 'legacy-42',
};

const adminDialogData = {
  title: 'Excluir evento',
  message: 'Esta ação remove o evento e não pode ser desfeita.',
  confirmLabel: 'Excluir',
  cancelLabel: 'Cancelar',
  fileName: 'inscricoes.csv',
  headers: ['Nome', 'E-mail', 'RA', 'Eventos'],
  previewRows: [
    { Nome: 'Ana Clara Silva', 'E-mail': 'ana@example.com', RA: '2026001', Eventos: 'event-1,event-2' },
    { Nome: 'Bruno Santos', 'E-mail': 'bruno@example.com', RA: '2026002', Eventos: 'event-2' },
  ],
  failedValues: ['sem-email@example.com'],
  createdCount: 12,
  duplicateCount: 2,
  failedCount: 1,
  inferredMatchType: 'EMAIL',
  createdSubscriptionCount: 10,
  updatedSubscriptionCount: 4,
  createdPeopleCount: 2,
  createdPeople: [personA, personB],
  failedRows: ['Linha 12: evento inexistente'],
  candidate: {
    id: 'merge-candidate-1',
    status: 'PENDING',
    confidence: 0.92,
    reason: 'Documento igual e e-mails semelhantes',
    personA,
    personB,
    createdAt: '2026-05-16T12:00:00.000Z',
    updatedAt: '2026-05-16T12:00:00.000Z',
  },
};

class StorybookAuthService {
  readonly user = () => ({
    sub: 'storybook-admin',
    preferredUsername: 'storybook-admin',
    email: 'admin@example.com',
    roles: ['admin'],
    scopes: ['profile', 'email'],
    permissions: [...EVENT_MANAGER_PERMISSION_CATALOG],
    claims: {
      name: 'Storybook Admin',
      preferred_username: 'storybook-admin',
      email: 'admin@example.com',
      is_onboarded: true,
    },
  });
  readonly roles = () => ['admin'];
  readonly scopes = () => ['profile', 'email'];
  readonly isAuthenticated = () => true;
  initialize = async () => undefined;
  login = async () => undefined;
  logout = async () => undefined;
}

function applyBrowserGlobals(network: string): void {
  Object.defineProperty(Navigator.prototype, 'onLine', {
    configurable: true,
    get: () => network !== 'offline',
  });
}

function applyColorScheme(theme: string): void {
  const colorScheme = theme === 'dark' ? 'dark' : 'light';
  document.documentElement.style.colorScheme = colorScheme;
  document.body.style.colorScheme = colorScheme;
}

if (originalNavigatorOnline) {
  Object.defineProperty(Navigator.prototype, 'onLine', originalNavigatorOnline);
}

const preview: Preview = {
  decorators: [
    applicationConfig({
      providers: [
        provideHttpClient(withFetch()),
        provideNoopAnimations(),
        provideRouter([], withDisabledInitialNavigation()),
        provideAppInitializer(() => {
          inject(MatIconRegistry).setDefaultFontSetClass('material-symbols-outlined');
        }),
        { provide: MAT_DIALOG_DATA, useValue: adminDialogData },
        { provide: MatDialogRef, useValue: dialogRefMock },
        { provide: AuthService, useClass: StorybookAuthService },
      ],
    }),
    (story, context) => {
      const theme = context.globals['theme'] === 'dark' ? 'dark' : 'light';
      const network = context.globals['network'] === 'offline' ? 'offline' : 'online';
      ensureStorybookGlobalStyles();
      applyBrowserGlobals(network);
      applyColorScheme(theme);
